TOKEN = "sbp_9d3bb1ca2c1b81ded0e6ebf813b66dd81e29896f"
URL = "https://api.supabase.com/v1/projects/amhfxaqolholacanqyas/database/query"
ok_count = 0
fail_count = 0

def run_sql(sql, label):
    global ok_count, fail_count
    payload = json.dumps({"query": sql})
    r = subprocess.run(["curl","-s","-X","POST",URL,"-H",f"Authorization: Bearer {TOKEN}","-H","Content-Type: application/json","-d",payload], capture_output=True, text=True, timeout=120)
    out = r.stdout.strip()
    if '"error"' in out or '"message"' in out:
        print(f"FAIL: {label} -> {out[:400]}")
        fail_count += 1
        return False
    print(f"OK: {label}")
    ok_count += 1
    return True

def O(o, a, d):
    return json.dumps([{"text":o[0],"score":100,"feedbackText":o[1]},{"text":a[0],"score":0,"feedbackText":a[1]},{"text":d[0],"score":-100,"feedbackText":d[1]}])

def E(s): return s.replace("'","''")

def build_insert(rows):
    vals = []
    for loc,cat,sc,tip,op,diff in rows:
        vals.append(f"('{E(loc)}','{E(cat)}','{E(sc)}','{E(tip)}','{E(op)}',{diff},'claude-opus-4-6',true)")
    return "INSERT INTO questions (locale,category,scenario_text,mindset_tip,options,difficulty,generated_by,is_active) VALUES\n" + ",\n".join(vals) + ";"

